# Generate pages
my $generated = 0;
for my $c (@cities) {
  my $page = $template;
  $page =~ s/\Q{{CITY}}\E/$c->{city}/g;
  $page =~ s/\Q{{CITY_SLUG}}\E/$c->{slug}/g;
  $page =~ s/\Q{{GEO_LAT}}\E/$c->{lat}/g;
  $page =~ s/\Q{{GEO_LNG}}\E/$c->{lng}/g;
  $page =~ s/\Q{{NEARBY_CITIES_PROSE}}\E/$c->{nearby_prose}/g;
  $page =~ s/\Q{{NEARBY_CITIES_LIST}}\E/$c->{nearby_list}/g;

  my $climate = qq{    <div class="qa-list">
      <article class="qa-card-light">
        <h3>$c->{h3_1}</h3>
        <p>$c->{p_1}</p>
      </article>

      <article class="qa-card-light">
        <h3>$c->{h3_2}</h3>
        <p>$c->{p_2}</p>
      </article>
    </div>};

  # Replace the climate placeholder comment block (handles Unicode box chars)
  $page =~ s/    <!--.*?\{\{CLIMATE_NOTE\}\}.*?-->/$climate/s;

  my $filename = "hvac-" . $c->{slug} . ".html";
  open(my $out, '>:encoding(UTF-8)', $filename) or die "Can't write $filename: $!";
  print $out $page;
  close $out;
  $generated++;
  print "  Wrote $filename\n";
}

print "Generated $generated city pages.\n";
